29	const PROCESSING_FEE = 5;
30	const FIRST_INSURANCE_RATE = 0.1;
31	
32	const BASE_PREMIUM: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_BASE = 60;
43	
44	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUM;
45	
46	const assertKnownItemTypes = (items: Item[]): void => {
47	  for (const item of items) {
48	    if (!isKnownItemType(item.type)) {
49	      throw new Error(`Unknown item type: ${item.type}`);
50	    }
51	  }
52	};
53	
54	const baseForGroup = (type: string, count: number): number => {
55	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
56	  return BASE_PREMIUM[type] * count;
57	};
58	
59	const countByType = (items: Item[]): Map<string, number> => {
60	  const counts = new Map<string, number>();
61	  for (const item of items) {
62	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
63	  }
64	  return counts;
65	};
66	
67	const sum = (numbers: number[]): number =>
68	  numbers.reduce((total, n) => total + n, 0);
69	
70	const groupBaseTotal = (items: Item[]): number => {
71	  const counts = countByType(items);
72	  return sum(
73	    Array.from(counts, ([type, count]) => baseForGroup(type, count)),
74	  );
75	};
76	
77	const itemSurchargeTotal = (items: Item[]): number =>
78	  sum(items.map((item) => surchargesFor(item)));
79	
80	const surchargesFor = (item: Item): number => {
81	  const base = BASE_PREMIUM[item.type];
82	  let total = 0;
83	  if (item.cursed) total += base * 0.5;
84	  if ((item.enchantment ?? 0) >= 5) total += base * 0.3;
85	  return total;
86	};
87	
88	const LOYALTY_THRESHOLD_YEARS = 2;
89	const LOYALTY_DISCOUNT_RATE = 0.2;
90	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
91	
92	export const quote = (
93	  customer: Customer,
94	  items: Item[],
95	  priorContracts: number,
96	): number => {
97	  assertKnownItemTypes(items);
98	  const groupBase = groupBaseTotal(items);
99	  const firstInsurance = groupBase * FIRST_INSURANCE_RATE;
100	  const surcharges = itemSurchargeTotal(items);
101	  const loyaltyDiscount =
102	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? groupBase * LOYALTY_DISCOUNT_RATE : 0;
103	  const followUpDiscount = priorContracts > 0 ? groupBase * FOLLOW_UP_DISCOUNT_RATE : 0;
104	  return Math.ceil(
105	    groupBase + firstInsurance + surcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
106	  );
107	};
108	
109	const DEDUCTIBLE = 100;
110	
111	export const claim = (
112	  policy: Policy,
113	  incident: Incident,
114	): { payout: number; remainingCap: number } => {
115	  const payout = incident.damages.reduce(
116	    (total, damage) => total + (damage.amount - DEDUCTIBLE),
117	    0,
118	  );
119	  return { payout, remainingCap: policy.remainingCap - payout };
120	};
